-- 设置转代溢出,默认user_id数据
update user_transfer_agent uta join user_info a on uta.site_code=a.site_code and uta.user_account=a.user_account set uta.user_id=a.user_id;
update agent_user_overflow auo join user_info a on auo.site_code=a.site_code and auo.member_name=a.user_account set auo.user_id=a.user_id;
-- 人工存款 人工取款 推荐改为不推荐
UPDATE system_recharge_way SET recommend_flag = 0 WHERE recharge_type_code = 'manual_recharge';


-- 修正存取类型id
UPDATE system_withdraw_way a JOIN system_withdraw_type b ON a.withdraw_type_code = b.withdraw_type_code AND a.currency_code = b.currency_code SET a.withdraw_type_id = b.id WHERE a.withdraw_type_id != b.id;

UPDATE system_recharge_way a JOIN system_recharge_type b ON a.recharge_type_code = b.recharge_code AND a.currency_code = b.currency_code SET a.recharge_type_id = b.id WHERE a.recharge_type_id != b.id;


update user_deposit_withdrawal u JOIN system_recharge_type s
ON u.currency_code = s.currency_code AND u.deposit_withdraw_type_code = s.recharge_code set u.deposit_withdraw_type_id = s.id   WHERE u.deposit_withdraw_type_code = s.recharge_code AND u.deposit_withdraw_type_id != s.id AND u.type = 1;

UPDATE user_deposit_withdrawal u JOIN system_withdraw_type s
ON u.currency_code = s.currency_code AND u.deposit_withdraw_type_code = s.withdraw_type_code set u.deposit_withdraw_type_id = s.id WHERE u.deposit_withdraw_type_code = s.withdraw_type_code and u.deposit_withdraw_type_id != s.id AND u.type = 2 ;

update agent_deposit_withdrawal u JOIN system_recharge_type s
ON u.currency_code = s.currency_code AND u.deposit_withdraw_type_code = s.recharge_code set u.deposit_withdraw_type_id = s.id   WHERE u.deposit_withdraw_type_code = s.recharge_code AND u.deposit_withdraw_type_id != s.id AND u.type = 1;

UPDATE agent_deposit_withdrawal u JOIN system_withdraw_type s
ON u.currency_code = s.currency_code AND u.deposit_withdraw_type_code = s.withdraw_type_code set u.deposit_withdraw_type_id = s.id WHERE u.deposit_withdraw_type_code = s.withdraw_type_code and u.deposit_withdraw_type_id != s.id AND u.type = 2 ;



