INSERT INTO site_vip_venue_exe (id, site_code, venue_type, experience, created_time, updated_time, creator, updater)
SELECT
    FLOOR(RAND() * 1000000000000000000),
    site_code,
    '8',
    1.00,
    UNIX_TIMESTAMP() * 1000,
    NULL,
    'fangyi666',
    NULL
FROM site_info;